public class Main {
    // method yang menerima 2 angka dan mengembalikan hasilnya
    static int tambah(int a, int b) {
        return a + b;
    }

    // method tanpa nilai balik (void) — cuma "melakukan" sesuatu
    static void sapa(String nama) {
        System.out.println("Halo, " + nama + "!");
    }

    public static void main(String[] args) {
        int hasil = tambah(4, 5);
        System.out.println(hasil); // 9
        sapa("Pais");              // Halo, Pais!
    }
}

