// Java otomatis memilih yang cocok berdasar jumlah argumen

public class Kucing {
    // atribut (sifat / data yang dimiliki)
    String nama;
    int umur;

    // constructor: dipanggil saat objek DIBUAT, untuk mengisi data awal
    Kucing(String nama, int umur) {
        this.nama = nama;
        this.umur = umur;
    }

    // method (kelakuan / hal yang bisa dilakukan)
    void meong() {
        System.out.println(nama + " bilang: Meoong!");
    }
}

public class Main {
    public static void main(String[] args) {
        Kucing oyen = new Kucing("Oyen", 2);
        Kucing kembang = new Kucing("Kembang", 1);

        oyen.meong();     // Oyen bilang: Meoong!
        kembang.meong();  // Kembang bilang: Meoong!

        System.out.println(oyen.nama + " umur " + oyen.umur);
    }
}

public class RekeningBank {
    private double saldo; // private = tidak bisa disentuh langsung dari luar

    public void setor(double jumlah) {
        if (jumlah > 0) saldo += jumlah;  // dijaga: tidak boleh setor minus
    }

    public double getSaldo() {
        return saldo;
    }
}

